def gen(rng, size):
    def rcode():
        return ''.join(str(rng.randint(0, 9)) for _ in range(4))
    target = rcode()
    while target == '0000':
        target = rcode()
    deads = set()
    m = rng.randint(1, min(size, 200))
    while len(deads) < m:
        c = rcode()
        if c != target:
            deads.add(c)
    return [list(deads), target]

