class Solution:
    def openLock(self, deadends, target):
        from collections import deque
        dead = set(deadends)
        if '0000' in dead:
            return -1
        if target == '0000':
            return 0
        visited = set(['0000'])
        q = deque([('0000', 0)])
        while q:
            state, d = q.popleft()
            for i in range(4):
                digit = int(state[i])
                for nd in (digit + 1) % 10, (digit - 1) % 10:
                    nxt = state[:i] + str(nd) + state[i+1:]
                    if nxt == target:
                        return d + 1
                    if nxt not in dead and nxt not in visited:
                        visited.add(nxt)
                        q.append((nxt, d + 1))
        return -1

