class Solution:
    def openLock(self, deadends, target):
        from collections import deque
        dead = set(deadends)
        if '0000' in dead:
            return -1
        q = deque([('0000', 0)])
        seen = {'0000'}
        while q:
            state, d = q.popleft()
            if state == target:
                return d
            for i in range(4):
                for delta in (1, -1):
                    nd = (int(state[i]) + delta) % 10
                    nxt = state[:i] + str(nd) + state[i+1:]
                    if nxt not in seen and nxt not in dead:
                        seen.add(nxt)
                        q.append((nxt, d + 1))
        return -1

