var openLock = function(deadends, target) {
    const dead = new Set(deadends);
    if (dead.has('0000')) return -1;
    const seen = new Set(['0000']);
    let queue = [['0000', 0]];
    while (queue.length) {
        const [state, d] = queue.shift();
        if (state === target) return d;
        for (let i = 0; i < 4; i++) {
            for (const delta of [1, -1]) {
                const nd = (Number(state[i]) + delta + 10) % 10;
                const nxt = state.slice(0, i) + nd + state.slice(i + 1);
                if (!seen.has(nxt) && !dead.has(nxt)) {
                    seen.add(nxt);
                    queue.push([nxt, d + 1]);
                }
            }
        }
    }
    return -1;
};
